   153→    @Test
   154→    void patternBGeneratesEnumFromCodeValue() {
   155→      OWLNamedIndividual code1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "code1"));
   156→      manager.addAxiom(ontology, df.getOWLAnnotationAssertionAxiom(
   157→          df.getOWLAnnotationProperty(IRI.create("http://www.w3.org/2004/02/skos/core#prefLabel")),
