    55→      OWLNamedIndividual active = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Active"));
    56→      OWLNamedIndividual inactive = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Inactive"));
    57→
    58→      // Add them to ontology with just owl:NamedIndividual type
    59→      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(active));
    60→      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(inactive));
    61→
    62→      // Create owl:oneOf restriction
    63→      var oneOf = factory.getOWLObjectOneOf(active, inactive);
    64→      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, oneOf);
    65→      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));
    66→
    67→      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
    68→      testClass.accept(visitor);
    69→
    70→      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
    71→      assertTrue(patterns.containsKey("hasCategory"));
