   102→      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(val2));
   103→
   104→      var oneOf = factory.getOWLObjectOneOf(val1, val2);
   105→      var restriction = factory.getOWLObjectExactCardinality(1, hasCategory, oneOf);
   106→      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));
   107→
   108→      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
   109→      testClass.accept(visitor);
   110→
   111→      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
   112→      assertTrue(patterns.containsKey("hasCategory"));
