package com.grl.component.schema;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.component.asg.OntologyConstants;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLAnnotationProperty;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyManager;

/**
 * Unit tests for taxonomy pattern detection in SchemaVisitor.
 */
class SchemaVisitorTaxonomyDetectionTest {

  private OWLOntologyManager manager;
  private OWLDataFactory factory;
  private OWLOntology ontology;
  private OWLClass testClass;
  private OWLClass owlThing;
  private OWLObjectProperty hasCategory;

  private static final String BASE_IRI = "http://example.org/test#";

  @BeforeEach
  void setUp() throws OWLOntologyCreationException {
    manager = OWLManager.createOWLOntologyManager();
    ontology = manager.createOntology(IRI.create(BASE_IRI + "ontology"));
    factory = manager.getOWLDataFactory();

    testClass = factory.getOWLClass(IRI.create(BASE_IRI + "TestClass"));
    owlThing = factory.getOWLThing();
    hasCategory = factory.getOWLObjectProperty(IRI.create(BASE_IRI + "hasCategory"));
  }

  @Nested
  class PatternADetection {

    @Test
    void detectsPatternAWithUntypedIndividuals() {
      // Create untyped individuals (only owl:NamedIndividual)
      OWLNamedIndividual active = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Active"));
      OWLNamedIndividual inactive = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Inactive"));

      // Add them to ontology with just owl:NamedIndividual type
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(active));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(inactive));

      // Create owl:oneOf restriction
      var oneOf = factory.getOWLObjectOneOf(active, inactive);
      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, oneOf);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_A, patterns.get("hasCategory").pattern());
      assertEquals(2, patterns.get("hasCategory").individuals().size());
    }

    @Test
    void patternAWithAllValuesFrom() {
      OWLNamedIndividual low = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Low"));
      OWLNamedIndividual high = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "High"));

      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(low));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(high));

      var oneOf = factory.getOWLObjectOneOf(low, high);
      var restriction = factory.getOWLObjectAllValuesFrom(hasCategory, oneOf);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_A, patterns.get("hasCategory").pattern());
    }

    @Test
    void patternAWithQualifiedCardinality() {
      OWLNamedIndividual val1 = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Value1"));
      OWLNamedIndividual val2 = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Value2"));

      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(val1));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(val2));

      var oneOf = factory.getOWLObjectOneOf(val1, val2);
      var restriction = factory.getOWLObjectExactCardinality(1, hasCategory, oneOf);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_A, patterns.get("hasCategory").pattern());
    }
  }

  @Nested
  class PatternBDetection {

    @Test
    void detectsPatternBWithTypedIndividuals() {
      // Create domain class for individuals
      OWLClass statusClass = factory.getOWLClass(IRI.create(BASE_IRI + "StatusCode"));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(statusClass));

      // Create typed individuals
      OWLNamedIndividual active = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "StatusActive"));
      OWLNamedIndividual inactive = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "StatusInactive"));

      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(statusClass, active));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(statusClass, inactive));

      // Create owl:oneOf restriction
      var oneOf = factory.getOWLObjectOneOf(active, inactive);
      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, oneOf);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_B, patterns.get("hasCategory").pattern());
    }

    @Test
    void patternBExtractsMetadata() {
      OWLClass codeClass = factory.getOWLClass(IRI.create(BASE_IRI + "Code"));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(codeClass));

      OWLNamedIndividual code1 = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Code1"));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(codeClass, code1));

      // Add skos:prefLabel annotation
      OWLAnnotationProperty prefLabel = factory.getOWLAnnotationProperty(OntologyConstants.SKOS_PREFLABEL);
      manager.addAxiom(ontology, factory.getOWLAnnotationAssertionAxiom(
          prefLabel, code1.getIRI(), factory.getOWLLiteral("Code One")));

      var oneOf = factory.getOWLObjectOneOf(code1);
      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, oneOf);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      TaxonomyInfo info = patterns.get("hasCategory");
      assertNotNull(info);
      assertEquals(TaxonomyPattern.PATTERN_B, info.pattern());

      // Check metadata was extracted
      assertFalse(info.metadata().isEmpty());
      TaxonomyInfo.IndividualMetadata meta = info.metadata().get("Code1");
      assertNotNull(meta);
      assertEquals("Code One", meta.displayName());
    }
  }

  @Nested
  class PatternCDetection {

    @Test
    void detectsPatternCWithNamedClass() {
      // Create taxonomy class without object property restrictions
      OWLClass environmentCode = factory.getOWLClass(IRI.create(BASE_IRI + "EnvironmentCode"));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(environmentCode));

      // Create some individuals of this class
      OWLNamedIndividual indoor = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Indoor"));
      OWLNamedIndividual outdoor = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Outdoor"));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(environmentCode, indoor));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(environmentCode, outdoor));

      // Create restriction to the named class
      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, environmentCode);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_C, patterns.get("hasCategory").pattern());
      assertNotNull(patterns.get("hasCategory").targetClass());
    }

    @Test
    void patternCDetectsHierarchy() {
      // Create parent taxonomy class
      OWLClass parentClass = factory.getOWLClass(IRI.create(BASE_IRI + "CategoryCode"));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(parentClass));

      // Create subclass
      OWLClass childClass = factory.getOWLClass(IRI.create(BASE_IRI + "SubCategory"));
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(childClass, parentClass));

      // Create individuals
      OWLNamedIndividual ind1 = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Cat1"));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(childClass, ind1));

      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, parentClass);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      TaxonomyInfo info = patterns.get("hasCategory");
      assertNotNull(info);
      assertEquals(TaxonomyPattern.PATTERN_C, info.pattern());
      assertTrue(info.hasHierarchy());
    }

    @Test
    void doesNotDetectPatternCForDomainClassWithObjectProperties() {
      // Create a class with object property restrictions (domain class, not taxonomy)
      OWLClass personClass = factory.getOWLClass(IRI.create(BASE_IRI + "Person"));
      OWLObjectProperty hasAddress = factory.getOWLObjectProperty(IRI.create(BASE_IRI + "hasAddress"));
      OWLClass addressClass = factory.getOWLClass(IRI.create(BASE_IRI + "Address"));

      // Add object property restriction to Person
      var addressRestriction = factory.getOWLObjectSomeValuesFrom(hasAddress, addressClass);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(personClass, addressRestriction));

      // Now use Person as range for our test property
      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, personClass);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      // Should not detect as taxonomy pattern because Person has object property restrictions
      assertFalse(patterns.containsKey("hasCategory"));
    }
  }

  @Nested
  class PatternDDetection {

    @Test
    void detectsPatternDWithSkosSubclass() {
      // Create SKOS Concept class
      OWLClass skosConcept = factory.getOWLClass(OntologyConstants.SKOS_CONCEPT);
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(skosConcept));

      // Create taxonomy class as subclass of skos:Concept
      OWLClass measurementContext = factory.getOWLClass(IRI.create(BASE_IRI + "MeasurementContextCode"));
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(measurementContext, skosConcept));

      // Create some individuals
      OWLNamedIndividual continuous = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Continuous"));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(measurementContext, continuous));

      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, measurementContext);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_D, patterns.get("hasCategory").pattern());
    }

    @Test
    void detectsPatternDWithInSchemeRestriction() {
      // Create concept scheme
      OWLNamedIndividual scheme = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "MyScheme"));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(scheme));

      // Create skos:inScheme property
      OWLObjectProperty inScheme = factory.getOWLObjectProperty(OntologyConstants.SKOS_IN_SCHEME);

      // Create taxonomy class with hasValue restriction on inScheme
      OWLClass codeClass = factory.getOWLClass(IRI.create(BASE_IRI + "CodeClass"));
      var inSchemeRestriction = factory.getOWLObjectHasValue(inScheme, scheme);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(codeClass, inSchemeRestriction));

      // Create individual
      OWLNamedIndividual code1 = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Code1"));
      manager.addAxiom(ontology, factory.getOWLClassAssertionAxiom(codeClass, code1));

      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, codeClass);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertTrue(patterns.containsKey("hasCategory"));
      assertEquals(TaxonomyPattern.PATTERN_D, patterns.get("hasCategory").pattern());
    }
  }

  @Nested
  class NoPatternDetection {

    @Test
    void noPatternForOwlThing() {
      var restriction = factory.getOWLObjectSomeValuesFrom(hasCategory, owlThing);
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, restriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      // owl:Thing should be ignored
      Map<String, TaxonomyInfo> patterns = visitor.getTaxonomyPatterns();
      assertFalse(patterns.containsKey("hasCategory"));
    }

    @Test
    void emptyOntologyNoPatterns() {
      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getTaxonomyPatterns().isEmpty());
    }
  }
}

