private TaxonomyInfo.IndividualGraph extractIndividualGraphDirect(OWLNamedIndividual individual) {
  OWLOntology ontology = context.getOntology();

  String code = getIndividualCode(individual);
  String displayName = getAnnotationValue(individual, "prefLabel");
  String definition = getAnnotationValue(individual, "definition");

  List<TaxonomyInfo.PropertyAssertion> assertions = new ArrayList<>();

  // Extract data property assertions from axioms
  ontology.dataPropertyAssertionAxioms(individual)
      .forEach(axiom -> {
        if (axiom.getProperty().isNamed()) {
          String propName = nameResolver.resolve(axiom.getProperty().asOWLDataProperty());
          OWLLiteral lit = axiom.getObject();
          assertions.add(new TaxonomyInfo.PropertyAssertion(
              propName,
              lit.getLiteral(),
              lit.getDatatype(),
              null
          ));
        }
      });

  // Extract object property assertions from axioms
  ontology.objectPropertyAssertionAxioms(individual)
      .forEach(axiom -> {
        if (axiom.getProperty().isNamed() && axiom.getObject().isNamed()) {
          String propName = nameResolver.resolve(axiom.getProperty().asOWLObjectProperty());
          assertions.add(new TaxonomyInfo.PropertyAssertion(
              propName,
              null,
              null,
              axiom.getObject().asOWLNamedIndividual()
          ));
        }
      });

  return new TaxonomyInfo.IndividualGraph(code, displayName, definition, assertions, individual);
}

