  @Nested
  class RequirednessTests {

    @Test
    void someValuesFromImpliesRequiredWhenEnforced() {
      MappingContext ctxWithReq = createContextWithEnforceRequiredness();

      OWLNamedIndividual val1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "Val1"));
      TaxonomyInfo info = TaxonomyInfo.patternA("field", List.of(val1));

      OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create(TEST_NS, "prop"));
      OWLClass rangeClass = df.getOWLClass(IRI.create(TEST_NS, "Range"));
      RestrictionInfo.SomeValuesFrom restriction = new RestrictionInfo.SomeValuesFrom(
          df.getOWLObjectSomeValuesFrom(prop, rangeClass));

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          ctxWithReq, info, Set.of(restriction), "Desc", "Label");

      assertTrue(mapper.isRequired());
    }

    @Test
    void noRestrictionsNotRequired() {
      MappingContext ctxWithReq = createContextWithEnforceRequiredness();

      OWLNamedIndividual val1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "Val1"));
      TaxonomyInfo info = TaxonomyInfo.patternA("field", List.of(val1));

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          ctxWithReq, info, Collections.emptySet(), "Desc", "Label");

      assertTrue(!mapper.isRequired());
    }
  }

  @Nested
  class ErrorHandling {

    @Test
    void nonePatternThrowsException() {
      TaxonomyInfo info = TaxonomyInfo.none("field");

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Collections.emptySet(), "Desc", "Label");

      assertThrows(IllegalArgumentException.class, mapper::getSchema);
    }

    @Test
    void patternCWithoutTargetClassThrowsException() {
      TaxonomyInfo info = new TaxonomyInfo(
          TaxonomyPattern.PATTERN_C,
          List.of(),
          null, // no target class
          false,
          null,
          "field",
          Map.of()
      );

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Collections.emptySet(), "Desc", "Label");

      assertThrows(IllegalStateException.class, mapper::getSchema);
    }
  }
