/**
 * Pattern B: Typed individuals with metadata.
 * Generates oneOf with const objects when maxIndividualDepth >= 1,
 * or falls back to simple string enum when maxIndividualDepth == 0.
 */
private Schema<?> mapPatternB() {
  int maxDepth = context.getMaxIndividualDepth();

  // Backward compatibility: depth 0 = simple string enum (old behavior)
  if (maxDepth == 0) {
    return mapPatternBLegacy();
  }

  // Generate oneOf with const objects
  List<TaxonomyInfo.IndividualGraph> graphs = info.individualGraphs();
  if (graphs.isEmpty()) {
    // Fallback if no graphs extracted (shouldn't happen normally)
    return mapPatternBLegacy();
  }

  List<Schema> individualSchemas = new ArrayList<>();
  for (TaxonomyInfo.IndividualGraph graph : graphs) {
    Schema<?> indSchema = buildIndividualSchema(graph, maxDepth, new HashSet<>());
    individualSchemas.add(indSchema);
  }

  ComposedSchema oneOfSchema = new ComposedSchema();
  oneOfSchema.setOneOf(individualSchemas);
  oneOfSchema.setDescription(description);

  return wrapInArrayIfNeeded(oneOfSchema);
}

/**
 * Legacy Pattern B: Simple string enum (for backward compatibility with maxIndividualDepth=0).
 */
private Schema<?> mapPatternBLegacy() {
  List<String> enumValues = new ArrayList<>();

  for (OWLNamedIndividual ind : info.individuals()) {
    String indName = nameResolver.resolve(ind);
    TaxonomyInfo.IndividualMetadata meta = info.metadata().get(indName);

    // Use codeValue if available, otherwise use label
    String codeValue = meta != null && meta.codeValue() != null
        ? meta.codeValue()
        : OntologyUtil.getTitle(ind, context.getOntology());
    enumValues.add(codeValue);
  }

