    95→   * Holds categorized axiom collections for the analyzed class.
    96→   *
    97→   * @param taxonomy axioms referencing named individuals (enum values)
    98→   * @param subClass direct SubClassOf axioms for the analyzed class
    99→   * @param superClass inherited axioms from the class hierarchy
   100→   */
   101→  private record AxiomCollection(
   102→      List<OWLSubClassOfAxiom> taxonomy,
   103→      List<OWLSubClassOfAxiom> subClass,
   104→      List<OWLSubClassOfAxiom> superClass) {}
   105→  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
   106→  private final MappingContext context;
   107→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   108→  private final String type;
   109→  private final OWLClass cls;
   110→  private final String classDescription;
   111→  private final String name;
   112→  private final Schema<?> schema;
   113→
   114→  public Schema<?> getSchema() {
   115→    return schema;
   116→  }
   117→
   118→  public String getName() {
   119→    return name;
   120→  }
   121→
   122→  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
   123→    this.context = context;
   124→    this.cls = cls;
   125→    this.classDescription = clsDescription;
   126→    this.type = "object";
   127→    this.name = nameResolver.resolve(cls);
   128→    this.schema = createSchema(cls);
   129→  }
   130→
   131→  /**
   132→   * Creates the OpenAPI schema for the analyzed OWL class.
   133→   *
   134→   * <p>This method orchestrates the schema generation by:
   135→   * <ol>
   136→   *   <li>Initializing the base ObjectSchema with metadata</li>
   137→   *   <li>Creating visitors to traverse class restrictions</li>
   138→   *   <li>Collecting relevant axioms from the ontology</li>
   139→   *   <li>Visiting axioms to gather property restrictions</li>
   140→   *   <li>Processing data, object, and taxonomy properties</li>
   141→   * </ol>
   142→   *
   143→   * @param analyzedClass the OWL class to generate a schema for
   144→   * @return the generated OpenAPI Schema object
   145→   */
   146→  private Schema<?> createSchema(OWLClass analyzedClass) {
   147→    Schema<?> schema = initializeResourceSchema();
   148→
   149→    VisitorPair visitors = createSchemaVisitors(analyzedClass);
   150→    AxiomCollection axioms = collectRelevantAxioms(analyzedClass);
   151→
   152→    visitAxiomsWithVisitors(visitors, axioms);
   153→
   154→    Map<String, Set<RestrictionInfo>> restrictions = mergeVisitorRestrictions(visitors);
   155→
   156→    processDataProperties(schema, visitors.dataPropertyVisitor(), restrictions, axioms.subClass());
   157→    processObjectProperties(schema, visitors.objectPropertyVisitor(), restrictions);
   158→    processTaxonomyProperties(schema, axioms.taxonomy(), visitors, restrictions);
   159→
   160→    if (schema.getProperties() == null || schema.getProperties().isEmpty()) {
   161→      logMissingPropertiesWarning(analyzedClass, axioms);
   162→    }
   163→
   164→    return schema;
   165→  }
   166→
   167→  /**
   168→   * Creates and configures the base ObjectSchema with standard properties.
   169→   *
   170→   * @return a new ObjectSchema configured with name, type, description, and OpenAPI 3.1 spec version
   171→   */
   172→  private Schema<?> initializeResourceSchema() {
   173→    Schema<?> resourceSchema = new ObjectSchema();
   174→    resourceSchema.setSpecVersion(SpecVersion.V31);
   175→    resourceSchema.setName(this.name);
   176→    resourceSchema.setDescription(this.classDescription);
   177→    resourceSchema.setType(this.type);
   178→    resourceSchema.setAdditionalProperties(false);
   179→    resourceSchema.setTitle(getLabel(this.cls));
   180→    return resourceSchema;
   181→  }
   182→
   183→  /**
   184→   * Creates paired SchemaVisitors for analyzing object and data property restrictions.
   185→   *
   186→   * <p>Both visitors traverse the same class hierarchy but collect different types
   187→   * of restrictions:
   188→   * <ul>
   189→   *   <li>Object visitor: collects SomeValuesFrom, AllValuesFrom, cardinality on object properties</li>
   190→   *   <li>Data visitor: collects DataSomeValuesFrom, DataAllValuesFrom, cardinality on data properties</li>
   191→   * </ul>
   192→   *
   193→   * @param analyzedClass the OWL class to analyze
   194→   * @return a record containing both configured visitors
   195→   */
   196→  private VisitorPair createSchemaVisitors(OWLClass analyzedClass) {
   197→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
   198→    OWLClass owlThing = dataFactory.getOWLThing();
   199→    return new VisitorPair(
   200→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false),
   201→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false));
   202→  }
   203→
   204→  /**
   205→   * Collects all relevant axioms for the analyzed class from the ontology.
   206→   *
   207→   * <p>Gathers three categories of axioms:
   208→   * <ul>
   209→   *   <li><b>Taxonomy axioms</b>: SubClassOf axioms referencing named individuals (enum values)</li>
   210→   *   <li><b>SubClass axioms</b>: Direct SubClassOf axioms for the analyzed class</li>
   211→   *   <li><b>SuperClass axioms</b>: Inherited axioms from the class hierarchy</li>
   212→   * </ul>
   213→   *
   214→   * @param analyzedClass the OWL class to collect axioms for
   215→   * @return a record containing categorized axiom lists
   216→   */
   217→  private AxiomCollection collectRelevantAxioms(OWLClass analyzedClass) {
   218→    OWLOntology ontology = context.getOntology();
   219→    return new AxiomCollection(
   220→        getTaxonomyAxioms(analyzedClass),
   221→        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
   222→        getSuperClassAxioms(analyzedClass, null).toList());
   223→  }
   224→
   225→  /**
   226→   * Visits axioms with the appropriate schema visitors to collect restrictions.
   227→   *
   228→   * <p>For each axiom, the superclass expression is visited by the object property
   229→   * visitor if it contains object properties, and by the data property visitor if
   230→   * it contains data properties.
   231→   *
   232→   * @param visitors the visitor pair to use
   233→   * @param axioms the axiom collection to process
   234→   */
   235→  private void visitAxiomsWithVisitors(VisitorPair visitors, AxiomCollection axioms) {
   236→    String schemaLabel = context.getSchemaLabel();
   237→
   238→    // Filter axioms to only those annotated with the target apiLabel
   239→    // This allows multiple API schemas to be generated from the same ontology
   240→    axioms.subClass().stream()
   241→        .filter(axiom -> !axioms.taxonomy().contains(axiom))
   242→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   243→        .map(OWLSubClassOfAxiom::getSuperClass)
   244→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   245→
   246→    axioms.superClass().stream()
   247→        .map(OWLSubClassOfAxiom::getSuperClass)
   248→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   249→  }
   250→
   251→  /**
   252→   * Visits a superclass expression with the appropriate visitors based on property types.
   253→   *
   254→   * @param superClass the class expression to visit
   255→   * @param visitors the visitor pair
   256→   */
   257→  private void visitSuperClass(OWLClassExpression superClass, VisitorPair visitors) {
   258→    if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
   259→      superClass.accept(visitors.objectPropertyVisitor());
   260→    }
   261→    if (!superClass.getDataPropertiesInSignature().isEmpty()) {
   262→      superClass.accept(visitors.dataPropertyVisitor());
   263→    }
   264→  }
   265→
   266→  /**
   267→   * Merges typed restrictions from both schema visitors into a unified map.
   268→   *
   269→   * <p>Combines restrictions keyed by property name. A single property may have
   270→   * multiple restrictions (e.g., both minCardinality and maxCardinality).
   271→   *
   272→   * @param visitors the visitor pair containing collected restrictions
   273→   * @return map of property name → set of RestrictionInfo for that property
   274→   */
   275→  private Map<String, Set<RestrictionInfo>> mergeVisitorRestrictions(VisitorPair visitors) {
   276→    Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   277→    Stream.of(visitors.objectPropertyVisitor(), visitors.dataPropertyVisitor())
   278→        .map(SchemaVisitor::getRestrictions)
   279→        .flatMap(map -> map.entrySet().stream())
   280→        .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
   281→            .addAll(entry.getValue()));
   282→    return restrictions;
   283→  }
   284→
   285→  /**
   286→   * Finds a data property in the ontology by its resolved name.
   287→   *
   288→   * @param propertyName the short-form property name (e.g., "firstName")
   289→   * @return the matching OWLDataProperty, or empty if not found
   290→   */
   291→  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
   292→    return context.getOntology()
   293→        .getDataPropertiesInSignature().stream()
   294→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   295→        .findFirst();
   296→  }
   297→
   298→  /**
   299→   * Finds an object property in the ontology by its resolved name.
   300→   *
   301→   * @param propertyName the short-form property name (e.g., "hasAddress")
   302→   * @return the matching OWLObjectProperty, or empty if not found
   303→   */
   304→  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
   305→    return context.getOntology()
   306→        .getObjectPropertiesInSignature().stream()
   307→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   308→        .findFirst();
   309→  }
   310→
   311→  /**
   312→   * Extracts range type/class names for a property from multiple sources.
   313→   *
   314→   * <p>Ranges are collected from:
   315→   * <ol>
   316→   *   <li>The SchemaVisitor's property range multimap (from restriction fillers)</li>
   317→   *   <li>The RestrictionInfo objects themselves (via getRangeNames)</li>
   318→   * </ol>
   319→   *
   320→   * @param propertyName the property to extract ranges for
   321→   * @param rangesFromVisitor multimap of property → range classes/datatypes from visitor
   322→   * @param restrictions map of property → RestrictionInfo set
   323→   * @return deduplicated list of range type names
   324→   */
   325→  private List<String> extractPropertyRanges(
   326→      String propertyName,
   327→      Multimap<String, ? extends OWLEntity> rangesFromVisitor,
   328→      Map<String, Set<RestrictionInfo>> restrictions) {
   329→    List<String> ranges = new ArrayList<>();
   330→
   331→    // Extract from visitor's range multimap
   332→    rangesFromVisitor.get(propertyName).stream()
   333→        .map(nameResolver::resolve)
   334→        .forEach(ranges::add);
   335→
   336→    // Also extract from restrictions themselves
   337→    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   338→    propertyRestrictions.stream()
   339→        .flatMap(r -> r.getRangeNames(nameResolver).stream())
   340→        .forEach(ranges::add);
   341→
   342→    // Remove duplicates to avoid treating single-range properties as multi-range
   343→    return ranges.stream().distinct().toList();
   344→  }
   345→
   346→  /**
   347→   * Extracts the example value for a data property from annotations.
   348→   *
   349→   * <p>Looks for skos:example annotations in two places (in order):
   350→   * <ol>
   351→   *   <li>On the SubClassOf axiom containing the property restriction</li>
   352→   *   <li>On the data property itself (as a default)</li>
   353→   * </ol>
   354→   *
   355→   * @param dataProperty the data property to find an example for
   356→   * @param subClassAxioms axioms that may contain restriction-level annotations
   357→   * @return the example value string, or null if none found
   358→   */
   359→  private String extractExampleValue(OWLDataProperty dataProperty, List<OWLSubClassOfAxiom> subClassAxioms) {
   360→    // First, look for a skos:example annotation on the restriction axiom itself
   361→    return subClassAxioms.stream()
   362→        .filter(axiom ->
   363→            axiom.getSuperClass() instanceof OWLDataRestriction restriction
   364→                && restriction.getProperty().asOWLDataProperty().getIRI().equals(dataProperty.getIRI()))
   365→        .map(axiom -> axiom.getAnnotations().stream()
   366→            .filter(annotation -> annotation.getProperty().getIRI().equals(OntologyConstants.SKOS_EXAMPLE))
   367→            .findFirst()
   368→            .flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
   369→        .flatMap(Optional::stream)
   370→        .findFirst()
   371→        // Fall back to the annotation on the data property itself
   372→        .orElse(OntologyUtil.defaultAnnotationsOf(dataProperty, context.getOntology())
   373→            .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
   374→  }
   375→
   376→  /**
   377→   * Processes all data properties and adds them to the schema.
   378→   *
   379→   * <p>For each data property discovered by the SchemaVisitor:
   380→   * <ol>
   381→   *   <li>Looks up the OWLDataProperty in the ontology</li>
   382→   *   <li>Extracts description, label, example, ranges, and enum values</li>
   383→   *   <li>Creates a DataPropertyMapper to generate the schema</li>
   384→   *   <li>Adds the property to the resource schema</li>
   385→   *   <li>Marks as required if restrictions indicate requiredness</li>
   386→   * </ol>
   387→   *
   388→   * @param schema the resource schema to add properties to
   389→   * @param dataVisitor visitor containing data property information
   390→   * @param restrictions merged restrictions map
   391→   * @param subClassAxioms axioms for extracting example annotations
   392→   */
   393→  private void processDataProperties(
   394→      Schema<?> schema,
   395→      SchemaVisitor dataVisitor,
   396→      Map<String, Set<RestrictionInfo>> restrictions,
   397→      List<OWLSubClassOfAxiom> subClassAxioms) {
   398→
   399→    Multimap<String, OWLDatatype> dataPropertyRanges = dataVisitor.getDataPropertyRanges();
   400→    Set<String> dataPropertyNames = dataVisitor.getDataPropertyNames();
   401→
   402→    for (String propertyName : dataPropertyNames) {
   403→      Optional<OWLDataProperty> dataPropertyOpt = findDataProperty(propertyName);
   404→      if (dataPropertyOpt.isEmpty()) {
   405→        continue;
   406→      }
   407→
   408→      OWLDataProperty dataProperty = dataPropertyOpt.get();
   409→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   410→
   411→      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
   412→      String label = getLabel(dataProperty);
   413→      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
   414→      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
   415→      List<String> enumValues = propertyRestrictions.stream()
   416→          .flatMap(r -> r.getEnumValues().stream())
   417→          .toList();
   418→
   419→      DataPropertyMapper mapper = new DataPropertyMapper(
   420→          context.getConfig(),
   421→          nameResolver.resolve(dataProperty),
   422→          label,
   423→          propertyDescription,
   424→          exampleValue,
   425→          propertyRestrictions,
   426→          enumValues,
   427→          rangeTypes);
   428→
   429→      try {
   430→        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
   431→        if (mapper.isRequired()) {
   432→          schema.addRequiredItem(mapper.getName());
   433→        }
   434→      } catch (Exception e) {
   435→        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
   436→      }
   437→    }
   438→  }
   439→
   440→  /**
   441→   * Processes all object properties and adds them to the schema.
   442→   *
   443→   * <p>For each object property discovered by the SchemaVisitor:
   444→   * <ol>
   445→   *   <li>Looks up the OWLObjectProperty in the ontology</li>
   446→   *   <li>Extracts description, label, and range classes</li>
   447→   *   <li>Creates an ObjectPropertyMapper to generate the schema</li>
   448→   *   <li>Adds the property to the resource schema</li>
   449→   *   <li>Marks as required if restrictions indicate requiredness</li>
   450→   * </ol>
   451→   *
   452→   * @param schema the resource schema to add properties to
   453→   * @param objectVisitor visitor containing object property information
   454→   * @param restrictions merged restrictions map
   455→   */
   456→  private void processObjectProperties(
   457→      Schema<?> schema,
   458→      SchemaVisitor objectVisitor,
   459→      Map<String, Set<RestrictionInfo>> restrictions) {
   460→
   461→    Multimap<String, OWLClass> objectPropertyRanges = objectVisitor.getObjectPropertyRanges();
   462→    Set<String> objectPropertyNames = objectVisitor.getObjectPropertyNames();
   463→
   464→    for (String propertyName : objectPropertyNames) {
   465→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   466→      if (objectPropertyOpt.isEmpty()) {
   467→        continue;
   468→      }
   469→
   470→      OWLObjectProperty objectProperty = objectPropertyOpt.get();
   471→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   472→
   473→      String propertyDescription = OntologyUtil.getDescription(objectProperty, context.getOntology());
   474→      String propertyLabel = getLabel(objectProperty);
   475→      List<String> rangeClasses = extractPropertyRanges(propertyName, objectPropertyRanges, restrictions);
   476→
   477→      ObjectPropertyMapper mapper = new ObjectPropertyMapper(
   478→          context, propertyName, propertyLabel, propertyDescription, propertyRestrictions, rangeClasses);
   479→
   480→      schema.addProperty(mapper.getName(), mapper.getSchema());
   481→      if (mapper.isRequired()) {
   482→        schema.addRequiredItem(mapper.getName());
   483→      }
   484→    }
   485→  }
   486→
   487→  /**
   488→   * Processes taxonomy axioms and adds enum properties to the schema.
   489→   *
   490→   * <p>This method first checks for taxonomy patterns detected by SchemaVisitor
   491→   * (patterns A, B, C, D) and uses TaxonomyPatternMapper for those. Falls back
   492→   * to existing logic for class-based taxonomies that weren't detected as patterns.
   493→   *
   494→   * <p>Supported patterns:
   495→   * <ul>
   496→   *   <li><b>Pattern A</b>: Inline enum with untyped individuals (owl:oneOf)</li>
   497→   *   <li><b>Pattern B</b>: Typed individuals with metadata (owl:oneOf)</li>
   498→   *   <li><b>Pattern C</b>: Class-based taxonomy (extensible)</li>
   499→   *   <li><b>Pattern D</b>: SKOS taxonomy (FHIR-compatible)</li>
   500→   *   <li><b>Legacy</b>: Direct individual references or class-based lookup</li>
   501→   * </ul>
   502→   *
   503→   * @param schema the resource schema to add taxonomy properties to
   504→   * @param taxonomyAxioms axioms identified as taxonomy definitions
   505→   * @param visitors the visitor pair containing detected taxonomy patterns
   506→   * @param restrictions merged restrictions map
   507→   */
   508→  private void processTaxonomyProperties(
   509→      Schema<?> schema,
   510→      List<OWLSubClassOfAxiom> taxonomyAxioms,
   511→      VisitorPair visitors,
   512→      Map<String, Set<RestrictionInfo>> restrictions) {
   513→
   514→    // First, process detected taxonomy patterns from SchemaVisitor
   515→    Set<String> processedProperties = new HashSet<>();
   516→    Map<String, TaxonomyInfo> taxonomyPatterns = extractTaxonomyPatterns(visitors);
   517→
   518→    for (Map.Entry<String, TaxonomyInfo> entry : taxonomyPatterns.entrySet()) {
   519→      String propertyName = entry.getKey();
   520→      TaxonomyInfo info = entry.getValue();
   521→
   522→      if (info.pattern() == TaxonomyPattern.NONE) {
   523→        continue;
   524→      }
   525→
   526→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   527→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   528→
   529→      String description = objectPropertyOpt
   530→          .map(prop -> OntologyUtil.getDescription(prop, context.getOntology()))
   531→          .orElse("");
   532→      String label = objectPropertyOpt
   533→          .map(this::getLabel)
   534→          .orElse(propertyName);
   535→
   536→      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
   537→          context, info, propertyRestrictions, description, label);
   538→
   539→      schema.addProperty(mapper.getName(), mapper.getSchema());
   540→      if (mapper.isRequired()) {
   541→        schema.addRequiredItem(mapper.getName());
   542→      }
   543→
   544→      processedProperties.add(propertyName);
   545→    }
   546→
   547→    // Fall back to legacy processing for taxonomy axioms not covered by pattern detection
   548→    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAxioms.stream()
   549→        .map(OWLSubClassOfAxiom::getSuperClass)
   550→        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream())
   551→        .filter(prop -> !processedProperties.contains(nameResolver.resolve(prop)))
   552→        .collect(Collectors.toSet());
   553→
   554→    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
   555→      for (OWLSubClassOfAxiom axiom : taxonomyAxioms) {
   556→        OWLClassExpression superCls = axiom.getSuperClass();
   557→
   558→        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {
   559→          if (!objectProperty.equals(taxonomyProperty)) {
   560→            continue;
   561→          }
   562→
   563→          Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
   564→          RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);
   565→
   566→          // Taxonomy detection: check if axiom references named individuals directly
   567→          Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();
   568→
   569→          if (!individualsInSignature.isEmpty()) {
   570→            // Direct individual reference - use individual labels as enum values
   571→            addTaxonomyPropertyToSchema(schema,
   572→                nameResolver.resolve(taxonomyProperty),
   573→                OntologyUtil.getDescription(cls, context.getOntology()),
   574→                getLabel(taxonomyProperty),
   575→                individualsInSignature.stream().map(this::getLabel).toList(),
   576→                taxonomyRestrictions);
   577→          } else {
   578→            // Indirect reference via class - look up individuals belonging to the class
   579→            for (OWLClass taxonomyClass : superCls.getClassesInSignature()) {
   580→              List<OWLNamedIndividual> individuals = EntitySearcher
   581→                  .getIndividuals(taxonomyClass, context.getOntology())
   582→                  .flatMap(Narrow.to(OWLNamedIndividual.class))
   583→                  .toList();
   584→
   585→              addTaxonomyPropertyToSchema(schema,
   586→                  taxonomyName(nameResolver.resolve(taxonomyClass)),
   587→                  OntologyUtil.getDescription(taxonomyClass, context.getOntology()),
   588→                  getLabel(taxonomyClass),
   589→                  individuals.stream().map(this::getLabel).toList(),
   590→                  taxonomyRestrictions);
   591→            }
   592→          }
   593→        }
   594→      }
   595→    }
   596→  }
   597→
   598→  /**
   599→   * Extracts taxonomy patterns from both schema visitors.
   600→   *
   601→   * @param visitors the visitor pair
   602→   * @return map of property name to TaxonomyInfo
   603→   */
   604→  private Map<String, TaxonomyInfo> extractTaxonomyPatterns(VisitorPair visitors) {
   605→    Map<String, TaxonomyInfo> patterns = new HashMap<>();
   606→    patterns.putAll(visitors.objectPropertyVisitor().getTaxonomyPatterns());
   607→    patterns.putAll(visitors.dataPropertyVisitor().getTaxonomyPatterns());
   608→    return patterns;
   609→  }
