   611→  /**
   612→   * Adds a taxonomy property to the schema.
   613→   *
   614→   * @param schema the schema to add the property to
   615→   * @param name the property name
   616→   * @param description the property description
   617→   * @param label the property label
   618→   * @param enumValues the list of allowed enum values
   619→   * @param restrictions the restrictions for this property
   620→   */
   621→  private void addTaxonomyPropertyToSchema(
   622→      Schema<?> schema,
   623→      String name,
   624→      String description,
   625→      String label,
   626→      List<String> enumValues,
   627→      Set<RestrictionInfo> restrictions) {
   628→    TaxonomyPropertyMapper mapper = new TaxonomyPropertyMapper(
   629→        context, name, description, label, enumValues, restrictions);
   630→    schema.addProperty(mapper.getName(), mapper.getTaxonomySchemaObject());
   631→    if (mapper.isRequired()) {
   632→      schema.addRequiredItem(mapper.getName());
   633→    }
   634→  }
