   636→  /**
   637→   * Logs a warning when no properties were found for a class.
   638→   *
   639→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   640→   * on the property restrictions, or that the schema label doesn't match.
   641→   *
   642→   * @param analyzedClass the class that had no mappable properties
   643→   * @param axioms all collected axioms (for diagnostic output)
   644→   */
   645→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   646→    logger.warning("No properties with " + OntologyConstants.apiLabel
   647→        + " annotation found for: " + analyzedClass);
   648→
   649→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   650→        .flatMap(Collection::stream)
   651→        .toList();
   652→
   653→    if (!allAxioms.isEmpty()) {
   654→      allAxioms.stream()
   655→          .map(axiom -> axiom.getSuperClass().toString())
   656→          .forEach(s -> logger.warning("\tPossible property: " + s));
   657→    }
   658→  }
   659→
   660→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   661→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   662→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   663→
   664→    return subAx.stream().filter(ax -> ax.annotations()
   665→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   666→      OWLClassExpression superCls = ax.getSuperClass();
   667→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   668→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   669→              .isEmpty()) || superCls.classesInSignature()
   670→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   671→    }).collect(Collectors.toList());
   672→  }
   673→
   674→  public String getSchemaName() {
   675→    return nameResolver.resolve(cls);
   676→  }
   677→
   678→  private String getSchemaAnnotation(String schema) {
   679→    return '"' + schema + '"' + "^^xsd:string";
   680→  }
   681→
   682→  private String taxonomyName(String taxonomy_name) {
   683→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   684→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   685→    }
   686→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   687→  }
   688→
   689→  private String getLabel(final OWLEntity entity) {
   690→    return OntologyUtil.getTitle(entity, context.getOntology());
   691→  }
   692→
   693→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   694→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   695→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   696→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   697→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   698→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   699→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   700→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   701→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   702→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   703→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   704→          if (superClass.isOWLClass()) {
   705→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   706→          }
   707→          if (owlSubClassOfAxiom.annotations()
   708→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   709→            superClassAxioms.add(owlSubClassOfAxiom);
   710→          }
   711→          return superClassAxioms.stream();
   712→        });
   713→  }
   714→
   715→}
