   100→public class SchemaVisitor implements OWLObjectVisitor {
   101→
   102→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
   103→
   104→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   105→  private final Set<OWLClass> processedClasses;
   106→  private final OWLClass cls;
   107→  private final OWLOntology onto;
   108→  String propertyName;
   109→  OWLClass owlThing;
   110→  Boolean range;
   111→
   112→
   113→  // Type-safe storage (private with unmodifiable getters)
   114→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   115→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   116→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   117→
   118→  // Property name tracking (minimal - just names, not full OWL objects)
   119→  private final Set<String> objectPropertyNames = new HashSet<>();
   120→  private final Set<String> dataPropertyNames = new HashSet<>();
   121→
   122→  // Taxonomy pattern tracking
   123→  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();
   124→
   125→  /**
   126→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   127→   *
   128→   * @param visitedClass the OWL class to analyze for restrictions
   129→   * @param onto         the ontology containing the class and its axioms
   130→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   131→   *                     no information)
   132→   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   133→   * @param range        whether this visitor is analyzing property ranges (typically false for
   134→   *                     initial call)
   135→   */
   136→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
   137→      String propertyName, Boolean range) {
   138→    processedClasses = new HashSet<>();
   139→    this.cls = visitedClass;
   140→    this.onto = onto;
   141→    this.propertyName = propertyName;
   142→    this.owlThing = owlThing;
   143→    this.range = range;
   144→  }
   145→
   146→  @Override
   147→  public void visit(OWLClass ce) {
   148→    if (!processedClasses.contains(ce)) {
   149→      processedClasses.add(ce);
   150→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   151→        ax.getSuperClass().accept(this);
   152→      }
   153→    }
   154→  }
   155→
   156→  @Override
   157→  public void visit(OWLObjectSomeValuesFrom ce) {
   158→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   159→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   160→      propertyName = cleanName(nameResolver.resolve(property));
   161→      objectPropertyNames.add(propertyName);
   162→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   163→          .add(new RestrictionInfo.SomeValuesFrom(ce));
   164→
   165→      // Detect taxonomy patterns
   166→      detectTaxonomyPattern(propertyName, ce.getFiller());
   167→    }
   168→
   169→    if (ce.getFiller() instanceof OWLObjectUnionOf ||
   170→        ce.getFiller() instanceof OWLObjectIntersectionOf ||
   171→        ce.getFiller() instanceof OWLObjectOneOf) {
   172→      ce.getFiller().accept(this);
   173→    } else {
   174→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   175→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   176→      } else {
   177→        logger.fine("Ignoring owl:Thing range " + propertyName);
   178→      }
   179→    }
   180→    propertyName = "";
   181→  }
   182→
   183→  @Override
   184→  public void visit(OWLObjectAllValuesFrom ce) {
   185→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   186→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   187→      propertyName = cleanName(nameResolver.resolve(property));
   188→      objectPropertyNames.add(propertyName);
   189→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   190→          .add(new RestrictionInfo.AllValuesFrom(ce));
   191→
   192→      // Detect taxonomy patterns
   193→      detectTaxonomyPattern(propertyName, ce.getFiller());
   194→    }
   195→
   196→    if (ce.getFiller() instanceof OWLObjectUnionOf
   197→        || ce.getFiller() instanceof OWLObjectIntersectionOf
   198→        || ce.getFiller() instanceof OWLObjectOneOf) {
   199→      ce.getFiller().accept(this);
   200→    } else {
   201→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   202→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   203→      } else {
   204→        logger.fine("Ignoring owl:Thing range " + propertyName);
   205→      }
   206→    }
   207→    propertyName = "";
   208→  }
   209→
   210→  @Override
   211→  public void visit(OWLObjectUnionOf ce) {
   212→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   213→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   214→        ce.getObjectPropertiesInSignature());
   215→  }
   216→
   217→  @Override
   218→  public void visit(OWLObjectIntersectionOf ce) {
   219→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   220→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   221→        ce.getObjectPropertiesInSignature());
   222→  }
   223→
   224→  @Override
   225→  public void visit(OWLObjectMinCardinality ce) {
   226→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   227→    setPropertiesWithCardinality(ce);
   228→  }
   229→
   230→  @Override
   231→  public void visit(OWLObjectMaxCardinality ce) {
   232→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   233→    setPropertiesWithCardinality(ce);
   234→  }
   235→
   236→  @Override
   237→  public void visit(OWLObjectExactCardinality ce) {
   238→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   239→    setPropertiesWithCardinality(ce);
   240→  }
   241→
   242→  @Override
   243→  public void visit(OWLObjectComplementOf ce) {
   244→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   245→    if (!propertyName.isEmpty()) {
   246→      ce.getOperand().accept(this);
   247→    }
   248→  }
   249→
   250→  @Override
   251→  public void visit(OWLObjectHasValue ce) {
   252→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   253→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   254→      propertyName = cleanName(nameResolver.resolve(property));
   255→      objectPropertyNames.add(propertyName);
   256→    }
   257→    propertyName = "";
   258→  }
   259→
   260→  @Override
