          // Check if hasCategory is an object with properties
          Object hasCategoryType = spec.read(
              "$.components.schemas.PatternTestResource.properties.hasSensorType.items.oneOf[" + i + "].properties.hasCategory.type");
          if ("object".equals(hasCategoryType)) {
            hasNestedCategory = true;
          } else {
            // Could also be a nested object without explicit type
            Object nestedCode = spec.read(
                "$.components.schemas.PatternTestResource.properties.hasSensorType.items.oneOf[" + i + "].properties.hasCategory.properties.code.const");
            if (nestedCode != null) {
              hasNestedCategory = true;
            }
          }
          break;
        }
      } catch (Exception e) {
        // Continue checking
      }
    }
    assertTrue(hasNestedCategory, "Analog individual should have nested hasCategory object");
  }

