package com.grl;

import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.*;
import org.semanticweb.owlapi.model.parameters.Imports;
import java.io.File;

class DebugPropertyAssertionTest {

  @Test
  void debugPropertyAssertions() throws Exception {
    OWLOntologyManager manager = OWLManager.createOWLOntologyManager();
    OWLOntologyLoaderConfiguration config = new OWLOntologyLoaderConfiguration();
    config = config.setMissingImportHandlingStrategy(MissingImportHandlingStrategy.SILENT);
    manager.setOntologyLoaderConfiguration(config);

    OWLOntology onto = manager.loadOntologyFromOntologyDocument(
        new File("target/test-output/taxonomy_patterns_test/ontology-flat.owl"));

    IRI analogIRI = IRI.create("https://example.com/taxonomy-patterns/SensorTypeAnalog");
    OWLDataFactory df = manager.getOWLDataFactory();
    OWLNamedIndividual analog = df.getOWLNamedIndividual(analogIRI);

    System.out.println("Individual: " + analog);
    System.out.println("\nData property assertions:");
    onto.dataPropertyAssertionAxioms(analog).forEach(System.out::println);

    System.out.println("\nObject property assertions:");
    onto.objectPropertyAssertionAxioms(analog).forEach(System.out::println);

    System.out.println("\nAnnotation assertions:");
    onto.annotationAssertionAxioms(analogIRI).forEach(System.out::println);

    System.out.println("\nAll axioms about this individual:");
    onto.axioms(analog).forEach(System.out::println);

    System.out.println("\nAll individuals in signature:");
    onto.individualsInSignature().limit(10).forEach(ind -> System.out.println("  " + ind.getIRI()));

    System.out.println("\nAll ObjectOneOf axioms:");
    onto.axioms()
        .flatMap(ax -> ax.nestedClassExpressions())
        .filter(ce -> ce instanceof OWLObjectOneOf)
        .map(ce -> (OWLObjectOneOf) ce)
        .limit(5)
        .forEach(oneOf -> {
          System.out.println("OneOf: " + oneOf);
          oneOf.individuals().forEach(ind -> System.out.println("  - " + ind));
        });
  }
}

